resource "aws_s3_bucket" "safe" {
  bucket = "my-bucket"
  acl = "private"
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
  tags = {
    Environment = "prod"
    Owner = "team"
    CostCenter = "engineering"
  }
}
